INSERT INTO public.intelligent_alerts (id, alert_type, severity, title, description, source_agent, affected_entities, trigger_condition, recommended_actions, auto_resolved, acknowledged_by, acknowledged_at, resolved_at, status, correlation_id, parent_alert_id, ttl_hours, created_at) VALUES ('495d9424-1295-4a1b-8ee4-bc7383170724', 'SLA_RISK', 'HIGH', 'SLA en riesgo: Incidencia INC-2026-0847 (P1) a 45min del breach', 'La incidencia P1 INC-2026-0847 (caída VPN Site-to-Site con proveedor SWIFT) lleva 3h15min abierta. El SLA P1 es de 4h. El técnico asignado FTE-067 reporta que necesita credenciales del proveedor SWIFT que aún no han sido proporcionadas. Si no se resuelve en 45 minutos, se producirá un SLA breach con penalización contractual estimada de €12,000.', 'AG-012', '{"service": "VPN SWIFT S2S", "incident": "INC-2026-0847", "assigned_technician": "FTE-067"}', '{"rule": "P1 incident > 75% of SLA window", "percentage": 81, "sla_minutes": 240, "elapsed_minutes": 195}', '["Escalar a vendor management para obtener credenciales SWIFT", "Asignar segundo técnico N3+ de Redes como backup", "Preparar comunicación al Comité de Dirección por posible breach"]', false, NULL, NULL, NULL, 'ACTIVE', 'CORR-2026-001', NULL, 2, '2026-03-19 21:40:09.809894+00');
INSERT INTO public.intelligent_alerts (id, alert_type, severity, title, description, source_agent, affected_entities, trigger_condition, recommended_actions, auto_resolved, acknowledged_by, acknowledged_at, resolved_at, status, correlation_id, parent_alert_id, ttl_hours, created_at) VALUES ('198bd4f1-8497-4b72-afbc-c78dc96fed3a', 'OVERALLOCATION', 'MEDIUM', 'Sobreasignación detectada: FTE-082 Carlos Ruiz al 94% de capacidad', 'El técnico FTE-082 (N3 Redes, Silo Infraestructura) tiene actualmente 3 incidencias P1/P2 abiertas y 2 proyectos BUILD asignados. Su carga calculada es del 94%, superando el umbral de 85%. Riesgo de burnout y degradación en tiempos de resolución. Historial: ha superado el 85% en 12 de los últimos 20 días laborables.', 'AG-012', '{"name": "Carlos Ruiz Navarro", "threshold": 85, "technician": "FTE-082", "current_load": 94}', '{"rule": "Technician load > 85% for > 3 consecutive days", "consecutive_days": 5, "current_load_pct": 94}', '["Redistribuir 1 incidencia P2 a FTE-091 (N3 Redes, carga 45%)", "Evaluar pausar asignación al proyecto PRJ0042 temporalmente", "Revisar con RRHH plan de descanso compensatorio"]', false, NULL, NULL, NULL, 'ACTIVE', NULL, NULL, 12, '2026-03-19 21:40:09.815933+00');
INSERT INTO public.intelligent_alerts (id, alert_type, severity, title, description, source_agent, affected_entities, trigger_condition, recommended_actions, auto_resolved, acknowledged_by, acknowledged_at, resolved_at, status, correlation_id, parent_alert_id, ttl_hours, created_at) VALUES ('352cf4b1-8a73-4390-ae34-1508cf065754', 'CASCADE_FAILURE', 'CRITICAL', 'CASCADA CRÍTICA: 3 servicios financieros afectados simultáneamente', 'Detectada correlación entre caída del servicio de pagos SWIFT (P1), degradación de Bizum (P2) y timeout en la pasarela de tarjetas. Los tres sistemas comparten el clúster Oracle Exadata que reporta latencia >500ms. Impacto estimado: 45,000 transacciones/hora bloqueadas. FTE-082 y FTE-091 ya asignados pero la carga actual es del 92%.', 'AG-012', '{"services": ["SWIFT Alliance", "Bizum Gateway", "Card Processing"], "infrastructure": "Oracle Exadata Cluster", "estimated_transactions_blocked": 45000}', '{"rule": "3+ CRITICAL alerts within 15min window", "window_minutes": 15, "correlated_alerts": 3}', '["Escalar a Nivel 4 de Infraestructura Oracle inmediatamente", "Activar DRP parcial para redirigir transacciones al nodo DR", "Notificar al responsable BCE de servicios de pago críticos", "Convocar War Room de Crisis con AG-001, AG-002, AG-004"]', false, NULL, NULL, '2026-03-19 21:41:46.062013+00', 'RESOLVED', 'CORR-2026-001', NULL, 4, '2026-03-19 21:40:09.800835+00');
INSERT INTO public.intelligent_alerts (id, alert_type, severity, title, description, source_agent, affected_entities, trigger_condition, recommended_actions, auto_resolved, acknowledged_by, acknowledged_at, resolved_at, status, correlation_id, parent_alert_id, ttl_hours, created_at) VALUES ('9e5838e6-2002-45f4-bd0a-5062b1df2cba', 'MILESTONE_RISK', 'LOW', 'Hito en riesgo: PRJ0034 ''Red Infraestructura BCC'' — entrega fase 2 en 4 días', 'El proyecto PRJ0034 tiene prevista la entrega del hito ''Despliegue switches core fase 2'' en 4 días laborables. Sin embargo, quedan 3 tareas sin completar en el WBS y el técnico principal (FTE-044) tiene una incidencia P2 abierta que consume el 40% de su tiempo. Probabilidad de retraso estimada: 65%.', 'AG-012', '{"project": "PRJ0034", "milestone": "Despliegue switches core fase 2", "pending_tasks": 3, "days_remaining": 4}', '{"rule": "Milestone < 5 days AND pending_tasks > 2", "delay_probability": 0.65}', '["Priorizar cierre de tareas pendientes del WBS", "Considerar asignar recurso adicional de Redes", "Comunicar riesgo al PM del proyecto"]', false, NULL, NULL, NULL, 'ACTIVE', NULL, NULL, 48, '2026-03-19 21:40:09.823437+00');
INSERT INTO public.intelligent_alerts (id, alert_type, severity, title, description, source_agent, affected_entities, trigger_condition, recommended_actions, auto_resolved, acknowledged_by, acknowledged_at, resolved_at, status, correlation_id, parent_alert_id, ttl_hours, created_at) VALUES ('1bcacb43-ca37-4c10-873b-9069f08aeb14', 'BURNOUT_RISK', 'MEDIUM', 'Riesgo burnout: 4 técnicos N3+ con carga sostenida >80% durante 2 semanas', 'Se detecta un patrón de sobreutilización en el pool de técnicos de nivel N3 y N4. FTE-082, FTE-067, FTE-091 y FTE-103 han mantenido una carga promedio superior al 80% durante las últimas 2 semanas laborables. Este patrón se correlaciona con un incremento del 15% en los tiempos medios de resolución (MTTR) del equipo.', 'AG-012', '{"technicians": ["FTE-082", "FTE-067", "FTE-091", "FTE-103"], "avg_load_pct": 84, "mttr_increase_pct": 15}', '{"rule": "3+ N3+ technicians > 80% load for > 10 working days", "affected_count": 4, "days_over_threshold": 14}', '["Evaluar contratación temporal de 2 recursos N3 de Redes y Sistemas", "Activar freeze parcial de proyectos BUILD no críticos", "Implementar rotación de guardias para descanso compensatorio", "Escalar a dirección de RRHH para plan de refuerzo"]', false, NULL, NULL, NULL, 'ACTIVE', 'CORR-2026-002', NULL, 72, '2026-03-19 21:40:09.831251+00');
