INSERT INTO public.postmortem_reports (id, incident_id, incident_priority, title, timeline, root_cause, root_cause_category, impact_assessment, corrective_actions, preventive_actions, lessons_learned, mttr_minutes, mtta_minutes, sla_breached, agents_involved, resources_involved, projects_impacted, review_status, approved_by, created_at, updated_at) VALUES ('7212e9ea-8007-4895-82e9-24a11a2d9a8f', 'INC-2026-0839', 'P1', 'Post-Mortem: Caída completa del servicio VPN Site-to-Site con SWIFT Alliance', '[{"time": "09:12", "event": "Monitorización detecta pérdida de conectividad VPN tunnel #3 con SWIFT"}, {"time": "09:15", "event": "AG-001 Dispatcher clasifica como P1 — servicio de pagos internacionales afectado"}, {"time": "09:18", "event": "AG-002 intenta asignar técnico N3 Redes — ninguno disponible (3 en incidencia, 1 vacaciones)"}, {"time": "09:47", "event": "Retraso de 32 min — se asigna FTE-067 (N2 Redes) tras escalado manual"}, {"time": "10:30", "event": "FTE-067 identifica que el certificado IKEv2 del túnel expiró sin renovación automática"}, {"time": "11:15", "event": "Contacto con SWIFT para regenerar certificado bilateral — requiere aprobación de security officer"}, {"time": "13:00", "event": "Security officer aprueba, se genera nuevo certificado"}, {"time": "14:22", "event": "Nuevo certificado instalado, túnel VPN restablecido"}, {"time": "14:54", "event": "Verificación completa — servicio de pagos SWIFT operativo al 100%"}]', 'El certificado IKEv2 del túnel VPN #3 con SWIFT Alliance expiró el 2026-03-17 sin que se activara la renovación automática. La causa raíz es doble: (1) El proceso de renovación automática de certificados estaba configurado solo para los túneles #1 y #2, omitiendo el #3 por un error en la configuración de Ansible. (2) No existía una alerta de monitorización para la fecha de expiración de certificados VPN.', 'INFRAESTRUCTURA', '{"financial": "€47,000 en transacciones SWIFT retrasadas + €15,000 penalización SLA", "technical": "124 transacciones SWIFT en cola durante 5h42min", "regulatory": "Notificación obligatoria al BCE por interrupción de servicio de pagos >2h", "reputational": "3 bancos corresponsales notificaron retrasos en pagos internacionales"}', '[{"owner": "FTE-067", "action": "Extender configuración Ansible de renovación automática a TODOS los túneles VPN", "deadline": "2026-03-22"}, {"owner": "FTE-082", "action": "Configurar alerta Nagios para certificados con <30 días de vida", "deadline": "2026-03-25"}, {"owner": "Jose Antonio Martinez", "action": "Crear runbook de escalado para incidencias P1 sin N3 disponible", "deadline": "2026-03-28"}]', '[{"action": "Auditoría trimestral de todos los certificados de infraestructura", "timeline": "30 días"}, {"action": "Implementar técnico de guardia N3+ para servicios críticos de pago", "timeline": "60 días"}, {"action": "Automatizar el proceso de renovación bilateral de certificados SWIFT", "timeline": "90 días"}]', '{"La automatización parcial es más peligrosa que la ausencia total — crea falsa sensación de seguridad","Los servicios de pago críticos (SWIFT, SEPA) requieren SLA de asignación <10 minutos, no <15","La dependencia de aprobaciones manuales de security officer es un bottleneck para P1 de certificados","Todo certificado de infraestructura debe tener alerta a 60, 30 y 7 días de expiración"}', 342, 47, true, '{AG-001,AG-002,AG-004,AG-012}', '{FTE-067,FTE-082}', '{PRJ0034,PRJ0043}', 'DRAFT', NULL, '2026-03-19 21:40:09.901468+00', '2026-03-19 21:40:09.901468+00');
INSERT INTO public.postmortem_reports (id, incident_id, incident_priority, title, timeline, root_cause, root_cause_category, impact_assessment, corrective_actions, preventive_actions, lessons_learned, mttr_minutes, mtta_minutes, sla_breached, agents_involved, resources_involved, projects_impacted, review_status, approved_by, created_at, updated_at) VALUES ('a7b26a83-85bc-4425-9805-a14d71322c65', 'INC-2026-0841', 'P2', 'Post-Mortem: Degradación rendimiento Bizum — latencia >2s en confirmaciones', '[{"time": "11:30", "event": "Usuarios internos reportan lentitud en confirmaciones Bizum"}, {"time": "11:45", "event": "AG-001 clasifica como P2 — servicio degradado pero funcional"}, {"time": "11:52", "event": "AG-002 asigna FTE-103 (N3 Aplicaciones, carga 55%)"}, {"time": "12:20", "event": "FTE-103 identifica query SQL sin índice en la tabla de transacciones de verificación"}, {"time": "12:45", "event": "Se crea índice en producción (operación online, sin downtime)"}, {"time": "13:00", "event": "Latencia normalizada a <200ms — servicio operativo"}]', 'Un desarrollo reciente (release v4.2.1 del 2026-03-14) añadió una nueva query de verificación anti-fraude que consultaba la tabla bizum_verifications sin índice en el campo transaction_hash. La query se ejecutaba en cada transacción y, al crecer el volumen a >50,000 transacciones/día, la latencia aumentó exponencialmente.', 'CODIGO', '{"financial": "Sin impacto financiero directo — transacciones se completaron con retraso", "technical": "Latencia media aumentó de 180ms a 2,300ms durante 1h30min", "regulatory": "Sin impacto regulatorio — servicio dentro de los umbrales de disponibilidad", "reputational": "15 reclamaciones de usuarios en 2 horas"}', '[{"owner": "FTE-103", "action": "Añadir revisión obligatoria de plan de ejecución SQL en pipeline CI/CD", "deadline": "2026-03-25"}, {"owner": "FTE-091", "action": "Crear suite de performance tests para queries críticas de Bizum", "deadline": "2026-03-30"}]', '[{"action": "Implementar análisis estático de queries SQL en pre-commit hooks", "timeline": "30 días"}, {"action": "Añadir dashboards de latencia por endpoint en Grafana con alertas", "timeline": "45 días"}]', '{"Las reviews de código deben incluir revisión del plan de ejecución de queries nuevas","Los tests de rendimiento deben ejecutarse con volúmenes realistas, no con datasets de test vacíos","La monitorización de latencia por endpoint es más útil que la latencia media global"}', 90, 7, false, '{AG-001,AG-002}', '{FTE-103}', '{}', 'DRAFT', NULL, '2026-03-19 21:40:09.908482+00', '2026-03-19 21:40:09.908482+00');
INSERT INTO public.postmortem_reports (id, incident_id, incident_priority, title, timeline, root_cause, root_cause_category, impact_assessment, corrective_actions, preventive_actions, lessons_learned, mttr_minutes, mtta_minutes, sla_breached, agents_involved, resources_involved, projects_impacted, review_status, approved_by, created_at, updated_at) VALUES ('7859ea31-2b4e-4689-846e-e08249d49eb6', 'INC-2026-0839', 'P1', 'Post-Mortem: Caída completa del servicio VPN Site-to-Site con SWIFT Alliance', '[{"time": "09:12", "event": "Monitorización detecta pérdida de conectividad VPN tunnel #3 con SWIFT"}, {"time": "09:15", "event": "AG-001 Dispatcher clasifica como P1 — servicio de pagos internacionales afectado"}, {"time": "09:18", "event": "AG-002 intenta asignar técnico N3 Redes — ninguno disponible (3 en incidencia, 1 vacaciones)"}, {"time": "09:47", "event": "Retraso de 32 min — se asigna FTE-067 (N2 Redes) tras escalado manual"}, {"time": "10:30", "event": "FTE-067 identifica que el certificado IKEv2 del túnel expiró sin renovación automática"}, {"time": "11:15", "event": "Contacto con SWIFT para regenerar certificado bilateral — requiere aprobación de security officer"}, {"time": "13:00", "event": "Security officer aprueba, se genera nuevo certificado"}, {"time": "14:22", "event": "Nuevo certificado instalado, túnel VPN restablecido"}, {"time": "14:54", "event": "Verificación completa — servicio de pagos SWIFT operativo al 100%"}]', 'El certificado IKEv2 del túnel VPN #3 con SWIFT Alliance expiró el 2026-03-17 sin que se activara la renovación automática. La causa raíz es doble: (1) El proceso de renovación automática de certificados estaba configurado solo para los túneles #1 y #2, omitiendo el #3 por un error en la configuración de Ansible. (2) No existía una alerta de monitorización para la fecha de expiración de certificados VPN.', 'INFRAESTRUCTURA', '{"financial": "€47,000 en transacciones SWIFT retrasadas + €15,000 penalización SLA", "technical": "124 transacciones SWIFT en cola durante 5h42min", "regulatory": "Notificación obligatoria al BCE por interrupción de servicio de pagos >2h", "reputational": "3 bancos corresponsales notificaron retrasos en pagos internacionales"}', '[{"owner": "FTE-067", "action": "Extender configuración Ansible de renovación automática a TODOS los túneles VPN", "deadline": "2026-03-22"}, {"owner": "FTE-082", "action": "Configurar alerta Nagios para certificados con <30 días de vida", "deadline": "2026-03-25"}, {"owner": "Jose Antonio Martinez", "action": "Crear runbook de escalado para incidencias P1 sin N3 disponible", "deadline": "2026-03-28"}]', '[{"action": "Auditoría trimestral de todos los certificados de infraestructura", "timeline": "30 días"}, {"action": "Implementar técnico de guardia N3+ para servicios críticos de pago", "timeline": "60 días"}, {"action": "Automatizar el proceso de renovación bilateral de certificados SWIFT", "timeline": "90 días"}]', '{"La automatización parcial es más peligrosa que la ausencia total — crea falsa sensación de seguridad","Los servicios de pago críticos (SWIFT, SEPA) requieren SLA de asignación <10 minutos, no <15","La dependencia de aprobaciones manuales de security officer es un bottleneck para P1 de certificados","Todo certificado de infraestructura debe tener alerta a 60, 30 y 7 días de expiración"}', 342, 47, true, '{AG-001,AG-002,AG-004,AG-012}', '{FTE-067,FTE-082}', '{PRJ0034,PRJ0043}', 'DRAFT', NULL, '2026-03-19 21:48:15.576877+00', '2026-03-19 21:48:15.576877+00');
