INSERT INTO public.whatif_simulations (id, simulation_name, scenario_type, input_params, baseline_snapshot, simulation_result, risk_score, confidence_level, recommendations, affected_projects, affected_resources, kpi_deltas, created_by, created_at) VALUES ('68f8ca27-fbf6-478f-8de0-4be3152e3e16', 'Cascada P1 — 3 incidencias críticas simultáneas en infraestructura financiera', 'P1_CASCADE', '{"description": "Simulación de escenario de crisis donde 3 incidencias P1 se producen simultáneamente afectando servicios financieros críticos: SWIFT, Bizum y procesamiento de tarjetas. Se evalúa la capacidad del pool de 150 técnicos para responder y el impacto en los proyectos BUILD activos.", "simultaneous_p1": 3, "affected_services": ["SWIFT Alliance", "Bizum", "Card Processing"]}', '{"available_n3_plus": 12, "total_technicians": 150, "active_p1_incidents": 1, "pool_utilization_pct": 68, "build_projects_active": 28}', '{"base_case": {"risk": 62, "cost_delta": "-€45K", "sla_impact": "-12%", "burnout_risk": 55, "timeline_delta": "+5d", "resolution_time_h": 6.0}, "best_case": {"risk": 35, "cost_delta": "€0", "sla_impact": "+0%", "burnout_risk": 30, "timeline_delta": "0d", "resolution_time_h": 3.5}, "worst_case": {"risk": 88, "cost_delta": "-€120K", "sla_impact": "-28%", "burnout_risk": 82, "timeline_delta": "+15d", "resolution_time_h": 12.0}}', 62.00, 0.78, '{"Establecer equipo de crisis pre-designado de 6 técnicos N3+ para escenarios de cascada","Activar freeze automático de BUILD cuando hay 2+ P1 simultáneas","Contratar 3 técnicos N3 de refuerzo en infraestructura financiera antes de Q2","Implementar failover automático para SWIFT y Bizum (reducir MTTR en 40%)","Crear procedimiento de comunicación BCE para cascadas que afecten servicios de pago"}', '{PRJ0034,PRJ0035,PRJ0043,PRJ0039,PRJ0041}', '{FTE-067,FTE-082,FTE-091,FTE-103,FTE-044,FTE-056}', '{"burnout_index": 55, "mttr_increase": "+35%", "estimated_cost": "-€45K", "sla_compliance": "-12%", "pool_utilization": "92%", "build_freeze_projects": 8}', 'AG-010', '2026-03-19 21:40:09.919283+00');
