### 3. Nueva Tabla en BD
```sql
CREATE TABLE documentacion_repositorio (
    id SERIAL PRIMARY KEY,
    titulo VARCHAR(255) NOT NULL,
    descripcion TEXT,
    tipo VARCHAR(50) NOT NULL, -- ''proyecto'', ''incidencia'', ''gobernanza''
    silo VARCHAR(10) NOT NULL, -- ''BUILD'', ''RUN''
    departamento VARCHAR(100),
    proyecto_id INTEGER REFERENCES cartera_build(id), -- NULL si no es específico de proyecto
    archivo_url VARCHAR(500), -- URL o path del archivo
    archivo_tipo VARCHAR(10), -- ''pdf'', ''docx'', ''md'', etc.
    tags TEXT[], -- Array de tags para búsqueda
    fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    fecha_actualizacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    creado_por VARCHAR(100),
    activo BOOLEAN DEFAULT true
);

CREATE INDEX idx_documentacion_tipo ON documentacion_repositorio(tipo);
CREATE INDEX idx_documentacion_silo ON documentacion_repositorio(silo);
CREATE INDEX idx_documentacion_departamento ON documentacion_repositorio(departamento);
CREATE INDEX idx_documentacion_tags ON documentacion_repositorio USING GIN(tags);
```

### 4. Endpoints API (agregar a main.py)
```python
@app.get("/api/documentacion")
async def get_documentacion(
    tipo: Optional[str] = None,
    silo: Optional[str] = None,
    departamento: Optional[str] = None,
    search: Optional[str] = None
):
    query = """
    SELECT d.*, cb.nombre_proyecto 
    FROM documentacion_repositorio d
    LEFT JOIN cartera_build cb ON d.proyecto_id = cb.id
    WHERE d.activo = true
    """
    params = []
    
    if tipo:
        query += " AND d.tipo = $" + str(len(params) + 1)
        params.append(tipo)
    
    if silo:
        query += " AND d.silo = $" + str(len(params) + 1)
        params.append(silo)
    
    if departamento:
        query += " AND d.departamento = $" + str(len(params) + 1)
        params.append(departamento)
    
    if search:
        query += " AND (d.titulo ILIKE $" + str(len(params) + 1) + " OR d.descripcion ILIKE $" + str(len(params) + 1) + ")"
        params.extend([f"%{search}%", f"%{search}%"])
    
    query += " ORDER BY d.fecha_actualizacion DESC"
    
    async with get_db_connection() as conn:
        rows = await conn.fetch(query, *params)
        return [dict(row) for row in rows]

