### 5. JavaScript para la Nueva Pestaña
```javascript
// Agregar al final del index.html
async function loadDocumentacion() {
    const tipo = document.getElementById(''docs-tipo'').value;
    const silo = document.getElementById(''docs-silo'').value;
    const departamento = document.getElementById(''docs-departamento'').value;
    const search = document.getElementById(''docs-search'').value;
    
    const params = new URLSearchParams();
    if (tipo) params.append(''tipo'', tipo);
    if (silo) params.append(''silo'', silo);
    if (departamento) params.append(''departamento'', departamento);
    if (search) params.append(''search'', search);
    
    try {
        const response = await fetch(`/api/documentacion?${params}`);
        const docs = await response.json();
        renderDocumentacion(docs);
    } catch (error) {
        console.error(''Error cargando documentación:'', error);
    }
}

function renderDocumentacion(docs) {
    const grid = document.querySelector(''.docs-grid'');
    grid.innerHTML = docs.map(doc => `
        <div class="doc-card">
            <div class="doc-header">
                <h3>${doc.titulo}</h3>
                <span class="doc-tipo ${doc.tipo}">${doc.tipo.toUpperCase()}</span>
                <span class="doc-silo ${doc.silo.toLowerCase()}">${doc.silo}</span>
            </div>
            <p class="doc-descripcion">${doc.descripcion || ''Sin descripción''}</p>
            <div class="doc-meta">
                <span>📁 ${doc.departamento}</span>
                ${doc.nombre_proyecto ? `<span>🎯 ${doc.nombre_proyecto}</span>` : ''''}
                <span>📅 ${new Date(doc.fecha_actualizacion).toLocaleDateString()}</span>
            </div>
            <div class="doc-actions">
                <button onclick="viewDocument(''${doc.archivo_url}'')" class="btn-primary">
                    📄 Ver Documento
                </button>
                <button onclick="downloadDocument(''${doc.archivo_url}'')" class="btn-secondary">
                    💾 Descargar
                </button>
            </div>
        </div>
    `).join('''');
}

