@app.get("/api/documentacion/{doc_id}/download")
async def download_documento(doc_id: int):
    """Genera URL de descarga directa desde Google Drive"""
    async with get_db_connection() as conn:
        doc = await conn.fetchrow("""
            SELECT drive_file_id, drive_share_url, titulo 
            FROM documentacion_repositorio 
            WHERE id = $1 AND activo = true
        """, doc_id)
        
        if not doc:
            raise HTTPException(status_code=404, detail="Documento no encontrado")
        
        # URL de descarga directa de Google Drive
        download_url = f"https://drive.google.com/uc?export=download&id={doc[''drive_file_id'']}"
        
        return {
            "download_url": download_url,
            "view_url": doc[''drive_share_url''],
            "titulo": doc[''titulo'']
        }
