// JavaScript para subida de documentos
async function uploadDocument(formData) {
    try {
        const response = await fetch(''/api/documentacion/upload'', {
            method: ''POST'',
            body: formData
        });
        
        if (response.ok) {
            const result = await response.json();
            showNotification(''✅ Documento subido correctamente'', ''success'');
            closeUploadModal();
            loadDocumentacion(); // Recargar lista
        } else {
            throw new Error(''Error en la subida'');
        }
    } catch (error) {
        showNotification(''❌ Error subiendo documento: '' + error.message, ''error'');
    }
}

function viewDocument(driveUrl) {
    window.open(driveUrl, ''_blank'');
}

async function downloadDocument(docId) {
    try {
        const response = await fetch(`/api/documentacion/${docId}/download`);
        const data = await response.json();
        
        // Abrir descarga en nueva ventana
        window.open(data.download_url, ''_blank'');
    } catch (error) {
        showNotification(''❌ Error descargando documento'', ''error'');
    }
}
